"use client";

import { useState } from "react";
import {
  Search,
  Pencil,
  Trash2,
  ChevronLeft,
  ChevronRight,
  MoreHorizontal,
} from "lucide-react";
import type { Article, ArticleStatus } from "../../types";

const STATUS_TABS: { label: string; value: ArticleStatus | "all" }[] = [
  { label: "Alles", value: "all" },
  { label: "Concept", value: "draft" },
  { label: "Gepubliceerd", value: "published" },
  { label: "Ingepland", value: "scheduled" },
  { label: "Gearchiveerd", value: "archived" },
];

const STATUS_BADGE_CLASSES: Record<ArticleStatus, string> = {
  draft: "bg-gray-100 text-gray-700",
  published: "bg-green-100 text-green-700",
  scheduled: "bg-blue-100 text-blue-700",
  archived: "bg-red-100 text-red-700",
};

const STATUS_LABELS: Record<ArticleStatus, string> = {
  draft: "Concept",
  published: "Gepubliceerd",
  scheduled: "Ingepland",
  archived: "Gearchiveerd",
};

interface ArticleListProps {
  articles: Article[];
  total: number;
  page: number;
  onPageChange: (page: number) => void;
  onSearch: (query: string) => void;
  onStatusFilter: (status: ArticleStatus | "all") => void;
  onDelete: (id: string) => void;
  onEdit: (id: string) => void;
  basePath?: string;
  pageSize?: number;
}

export function ArticleList({
  articles,
  total,
  page,
  onPageChange,
  onSearch,
  onStatusFilter,
  onDelete,
  onEdit,
  basePath = "/admin/artikelen",
  pageSize = 20,
}: ArticleListProps) {
  const [searchValue, setSearchValue] = useState("");
  const [activeTab, setActiveTab] = useState<ArticleStatus | "all">("all");
  const [deleteConfirm, setDeleteConfirm] = useState<string | null>(null);

  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function handleSearchChange(e: React.ChangeEvent<HTMLInputElement>) {
    const value = e.target.value;
    setSearchValue(value);
    onSearch(value);
  }

  function handleTabChange(status: ArticleStatus | "all") {
    setActiveTab(status);
    onStatusFilter(status);
  }

  function handleDelete(id: string) {
    if (deleteConfirm === id) {
      onDelete(id);
      setDeleteConfirm(null);
    } else {
      setDeleteConfirm(id);
    }
  }

  function formatDate(dateStr: string | null): string {
    if (!dateStr) return "-";
    return new Date(dateStr).toLocaleDateString("nl-NL", {
      day: "numeric",
      month: "short",
      year: "numeric",
    });
  }

  return (
    <div className="space-y-4">
      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
        <input
          type="text"
          value={searchValue}
          onChange={handleSearchChange}
          placeholder="Zoek artikelen..."
          className="w-full rounded-lg border border-border bg-secondary px-10 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      {/* Status filter tabs */}
      <div className="flex gap-1 rounded-lg bg-muted p-1">
        {STATUS_TABS.map((tab) => (
          <button
            key={tab.value}
            onClick={() => handleTabChange(tab.value)}
            className={`rounded-md px-3 py-1.5 text-sm font-medium transition-colors ${
              activeTab === tab.value
                ? "bg-white text-foreground shadow-sm"
                : "text-muted-foreground hover:text-foreground"
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-lg border border-border">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-border bg-muted">
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">
                Titel
              </th>
              <th className="px-4 py-3 text-left font-medium text-muted-foreground">
                Status
              </th>
              <th className="hidden px-4 py-3 text-left font-medium text-muted-foreground md:table-cell">
                Categorie
              </th>
              <th className="hidden px-4 py-3 text-left font-medium text-muted-foreground sm:table-cell">
                Datum
              </th>
              <th className="px-4 py-3 text-right font-medium text-muted-foreground">
                Acties
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {articles.length === 0 ? (
              <tr>
                <td
                  colSpan={5}
                  className="px-4 py-8 text-center text-muted-foreground"
                >
                  Geen artikelen gevonden.
                </td>
              </tr>
            ) : (
              articles.map((article) => (
                <tr
                  key={article.id}
                  className="bg-white transition-colors hover:bg-muted/50"
                >
                  <td className="px-4 py-3">
                    <a
                      href={`${basePath}/${article.id}`}
                      className="font-medium text-foreground hover:text-primary"
                    >
                      {article.title}
                    </a>
                    <p className="mt-0.5 text-xs text-muted-foreground">
                      /{article.slug}
                    </p>
                  </td>
                  <td className="px-4 py-3">
                    <span
                      className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium ${STATUS_BADGE_CLASSES[article.status]}`}
                    >
                      {STATUS_LABELS[article.status]}
                    </span>
                  </td>
                  <td className="hidden px-4 py-3 text-muted-foreground md:table-cell">
                    {article.category?.name ?? "-"}
                  </td>
                  <td className="hidden px-4 py-3 text-muted-foreground sm:table-cell">
                    {formatDate(
                      article.published_at ??
                        article.scheduled_at ??
                        article.created_at,
                    )}
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center justify-end gap-1">
                      <button
                        type="button"
                        onClick={() => onEdit(article.id)}
                        className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground"
                        title="Bewerken"
                      >
                        <Pencil className="h-4 w-4" />
                      </button>
                      <button
                        type="button"
                        onClick={() => handleDelete(article.id)}
                        className={`rounded-md p-1.5 transition-colors ${
                          deleteConfirm === article.id
                            ? "bg-red-100 text-red-600"
                            : "text-muted-foreground hover:bg-muted hover:text-foreground"
                        }`}
                        title={
                          deleteConfirm === article.id
                            ? "Klik nogmaals om te verwijderen"
                            : "Verwijderen"
                        }
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between">
          <p className="text-sm text-muted-foreground">
            {total} artikel{total !== 1 ? "en" : ""} totaal
          </p>
          <div className="flex items-center gap-1">
            <button
              type="button"
              onClick={() => onPageChange(page - 1)}
              disabled={page <= 1}
              className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground disabled:opacity-50 disabled:hover:bg-transparent"
            >
              <ChevronLeft className="h-4 w-4" />
            </button>
            {Array.from({ length: totalPages }, (_, i) => i + 1)
              .filter((p) => {
                if (totalPages <= 7) return true;
                if (p === 1 || p === totalPages) return true;
                if (Math.abs(p - page) <= 1) return true;
                return false;
              })
              .reduce<(number | "ellipsis")[]>((acc, p, idx, arr) => {
                if (idx > 0 && p - (arr[idx - 1] as number) > 1) {
                  acc.push("ellipsis");
                }
                acc.push(p);
                return acc;
              }, [])
              .map((item, idx) =>
                item === "ellipsis" ? (
                  <span
                    key={`ellipsis-${idx}`}
                    className="px-1 text-muted-foreground"
                  >
                    <MoreHorizontal className="h-4 w-4" />
                  </span>
                ) : (
                  <button
                    key={item}
                    type="button"
                    onClick={() => onPageChange(item)}
                    className={`min-w-[2rem] rounded-md px-2 py-1 text-sm font-medium ${
                      page === item
                        ? "bg-primary text-white"
                        : "text-muted-foreground hover:bg-muted hover:text-foreground"
                    }`}
                  >
                    {item}
                  </button>
                ),
              )}
            <button
              type="button"
              onClick={() => onPageChange(page + 1)}
              disabled={page >= totalPages}
              className="rounded-md p-1.5 text-muted-foreground hover:bg-muted hover:text-foreground disabled:opacity-50 disabled:hover:bg-transparent"
            >
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
