"use client";

import { Eye, FileText, BarChart3 } from "lucide-react";
import type { ArticleStats } from "../../types";

interface AnalyticsDashboardProps {
  stats: {
    totalViews: number;
    articleCount: number;
    popularArticles: ArticleStats[];
  };
}

function formatNumber(num: number): string {
  if (num >= 1_000_000) {
    return `${(num / 1_000_000).toFixed(1)}M`;
  }
  if (num >= 1_000) {
    return `${(num / 1_000).toFixed(1)}K`;
  }
  return num.toLocaleString("nl-NL");
}

export function AnalyticsDashboard({ stats }: AnalyticsDashboardProps) {
  const mostViewed = stats.popularArticles[0];

  return (
    <div className="space-y-6">
      {/* Stats cards */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
        {/* Total views */}
        <div className="rounded-lg border border-border bg-white p-6">
          <div className="flex items-center gap-3">
            <div className="rounded-lg bg-primary/10 p-2.5">
              <Eye className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-sm text-muted-foreground">
                Weergaven (30 dagen)
              </p>
              <p className="text-2xl font-bold text-foreground">
                {formatNumber(stats.totalViews)}
              </p>
            </div>
          </div>
        </div>

        {/* Articles published */}
        <div className="rounded-lg border border-border bg-white p-6">
          <div className="flex items-center gap-3">
            <div className="rounded-lg bg-green-100 p-2.5">
              <FileText className="h-5 w-5 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-muted-foreground">
                Gepubliceerde artikelen
              </p>
              <p className="text-2xl font-bold text-foreground">
                {formatNumber(stats.articleCount)}
              </p>
            </div>
          </div>
        </div>

        {/* Most viewed */}
        <div className="rounded-lg border border-border bg-white p-6 sm:col-span-2 lg:col-span-1">
          <div className="flex items-center gap-3">
            <div className="rounded-lg bg-blue-100 p-2.5">
              <BarChart3 className="h-5 w-5 text-blue-600" />
            </div>
            <div className="min-w-0 flex-1">
              <p className="text-sm text-muted-foreground">Meest bekeken</p>
              {mostViewed ? (
                <>
                  <p
                    className="truncate text-sm font-semibold text-foreground"
                    title={mostViewed.title}
                  >
                    {mostViewed.title}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {formatNumber(mostViewed.total_views)} weergaven
                  </p>
                </>
              ) : (
                <p className="text-sm text-muted-foreground">
                  Geen data beschikbaar
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Top 10 articles table */}
      <div className="rounded-lg border border-border">
        <div className="border-b border-border px-4 py-3">
          <h3 className="flex items-center gap-2 text-sm font-semibold text-foreground">
            <BarChart3 className="h-4 w-4" />
            Top 10 artikelen
          </h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-border bg-muted">
                <th className="px-4 py-2.5 text-left font-medium text-muted-foreground">
                  #
                </th>
                <th className="px-4 py-2.5 text-left font-medium text-muted-foreground">
                  Artikel
                </th>
                <th className="px-4 py-2.5 text-right font-medium text-muted-foreground">
                  Totaal
                </th>
                <th className="hidden px-4 py-2.5 text-right font-medium text-muted-foreground sm:table-cell">
                  Vandaag
                </th>
                <th className="hidden px-4 py-2.5 text-right font-medium text-muted-foreground md:table-cell">
                  Deze week
                </th>
                <th className="hidden px-4 py-2.5 text-right font-medium text-muted-foreground lg:table-cell">
                  Deze maand
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {stats.popularArticles.length === 0 ? (
                <tr>
                  <td
                    colSpan={6}
                    className="px-4 py-8 text-center text-muted-foreground"
                  >
                    Nog geen weergavedata beschikbaar.
                  </td>
                </tr>
              ) : (
                stats.popularArticles.slice(0, 10).map((article, index) => (
                  <tr
                    key={article.article_id}
                    className="bg-white transition-colors hover:bg-muted/50"
                  >
                    <td className="px-4 py-2.5 text-muted-foreground">
                      {index + 1}
                    </td>
                    <td className="max-w-xs px-4 py-2.5">
                      <p
                        className="truncate font-medium text-foreground"
                        title={article.title}
                      >
                        {article.title}
                      </p>
                      <p className="truncate text-xs text-muted-foreground">
                        /{article.slug}
                      </p>
                    </td>
                    <td className="px-4 py-2.5 text-right font-medium text-foreground">
                      {formatNumber(article.total_views)}
                    </td>
                    <td className="hidden px-4 py-2.5 text-right text-muted-foreground sm:table-cell">
                      {formatNumber(article.views_today)}
                    </td>
                    <td className="hidden px-4 py-2.5 text-right text-muted-foreground md:table-cell">
                      {formatNumber(article.views_this_week)}
                    </td>
                    <td className="hidden px-4 py-2.5 text-right text-muted-foreground lg:table-cell">
                      {formatNumber(article.views_this_month)}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
