"use client";

import { useState, useEffect } from "react";
import {
  Save,
  Send,
  Clock,
  ChevronDown,
  ChevronUp,
  X,
  Loader2,
  Plus,
  Calendar,
} from "lucide-react";
import type { Article, Category, Tag } from "../../types";
import { slugify } from "../../utils";
import { TiptapEditor } from "../editor/tiptap-editor";
import { ImageUpload } from "../editor/image-upload";

interface ArticleFormData {
  title: string;
  slug: string;
  excerpt: string;
  content: Record<string, unknown>;
  content_html: string;
  category_id: string;
  featured_image: string | null;
  meta_title: string;
  meta_description: string;
  og_image: string;
  canonical_url: string;
  scheduled_at: string;
}

interface ArticleFormProps {
  article?: Article;
  categories: Category[];
  tags: Tag[];
  onSave: (data: Partial<ArticleFormData>, tagIds: string[]) => void;
  onPublish: (data: Partial<ArticleFormData>, tagIds: string[]) => void;
  onSchedule: (data: Partial<ArticleFormData>, tagIds: string[]) => void;
  onImageUpload: (file: File) => Promise<string>;
}

export function ArticleForm({
  article,
  categories,
  tags,
  onSave,
  onPublish,
  onSchedule,
  onImageUpload,
}: ArticleFormProps) {
  const [title, setTitle] = useState(article?.title ?? "");
  const [slug, setSlug] = useState(article?.slug ?? "");
  const [slugManuallyEdited, setSlugManuallyEdited] = useState(false);
  const [excerpt, setExcerpt] = useState(article?.excerpt ?? "");
  const [content, setContent] = useState<Record<string, unknown>>(
    article?.content ?? {},
  );
  const [contentHtml, setContentHtml] = useState(article?.content_html ?? "");
  const [categoryId, setCategoryId] = useState(article?.category_id ?? "");
  const [selectedTagIds, setSelectedTagIds] = useState<string[]>(
    article?.tags?.map((t) => t.id) ?? [],
  );
  const [newTagName, setNewTagName] = useState("");
  const [showNewTagInput, setShowNewTagInput] = useState(false);
  const [featuredImage, setFeaturedImage] = useState<string | null>(
    article?.featured_image ?? null,
  );

  // SEO fields
  const [seoOpen, setSeoOpen] = useState(false);
  const [metaTitle, setMetaTitle] = useState(article?.meta_title ?? "");
  const [metaDescription, setMetaDescription] = useState(
    article?.meta_description ?? "",
  );
  const [ogImage, setOgImage] = useState(article?.og_image ?? "");
  const [canonicalUrl, setCanonicalUrl] = useState(
    article?.canonical_url ?? "",
  );

  // Schedule
  const [scheduledAt, setScheduledAt] = useState(
    article?.scheduled_at
      ? new Date(article.scheduled_at).toISOString().slice(0, 16)
      : "",
  );

  const [isSaving, setIsSaving] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [isScheduling, setIsScheduling] = useState(false);

  // Auto-generate slug from title
  useEffect(() => {
    if (!slugManuallyEdited && title) {
      setSlug(slugify(title));
    }
  }, [title, slugManuallyEdited]);

  function getFormData(): Partial<ArticleFormData> {
    return {
      title,
      slug,
      excerpt: excerpt || undefined,
      content,
      content_html: contentHtml,
      category_id: categoryId || undefined,
      featured_image: featuredImage,
      meta_title: metaTitle || undefined,
      meta_description: metaDescription || undefined,
      og_image: ogImage || undefined,
      canonical_url: canonicalUrl || undefined,
      scheduled_at: scheduledAt ? new Date(scheduledAt).toISOString() : undefined,
    };
  }

  async function handleSave() {
    setIsSaving(true);
    try {
      onSave(getFormData(), selectedTagIds);
    } finally {
      setIsSaving(false);
    }
  }

  async function handlePublish() {
    setIsPublishing(true);
    try {
      onPublish(getFormData(), selectedTagIds);
    } finally {
      setIsPublishing(false);
    }
  }

  async function handleSchedule() {
    if (!scheduledAt) return;
    setIsScheduling(true);
    try {
      onSchedule(getFormData(), selectedTagIds);
    } finally {
      setIsScheduling(false);
    }
  }

  function handleEditorChange(json: Record<string, unknown>, html: string) {
    setContent(json);
    setContentHtml(html);
  }

  function toggleTag(tagId: string) {
    setSelectedTagIds((prev) =>
      prev.includes(tagId)
        ? prev.filter((id) => id !== tagId)
        : [...prev, tagId],
    );
  }

  const filteredTags = newTagName
    ? tags.filter((t) =>
        t.name.toLowerCase().includes(newTagName.toLowerCase()),
      )
    : tags;

  return (
    <div className="mx-auto max-w-4xl space-y-6">
      {/* Title */}
      <input
        type="text"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        placeholder="Titel van het artikel..."
        className="w-full border-0 bg-transparent text-3xl font-bold text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-0"
      />

      {/* Slug */}
      <div className="flex items-center gap-2">
        <span className="text-sm text-muted-foreground">/</span>
        <input
          type="text"
          value={slug}
          onChange={(e) => {
            setSlug(e.target.value);
            setSlugManuallyEdited(true);
          }}
          onBlur={() => {
            if (slug) {
              setSlug(slugify(slug));
            }
          }}
          placeholder="artikel-slug"
          className="flex-1 border-0 bg-transparent text-sm text-muted-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-0"
        />
        {slugManuallyEdited && (
          <button
            type="button"
            onClick={() => {
              setSlugManuallyEdited(false);
              setSlug(slugify(title));
            }}
            className="text-xs text-primary hover:underline"
          >
            Auto-genereren
          </button>
        )}
      </div>

      {/* Excerpt */}
      <div>
        <label className="mb-1 block text-sm font-medium text-foreground">
          Samenvatting
        </label>
        <textarea
          value={excerpt}
          onChange={(e) => setExcerpt(e.target.value)}
          placeholder="Korte samenvatting van het artikel..."
          rows={3}
          className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
      </div>

      {/* Content Editor */}
      <div>
        <label className="mb-1 block text-sm font-medium text-foreground">
          Inhoud
        </label>
        <TiptapEditor
          content={content}
          onChange={handleEditorChange}
          onImageUpload={onImageUpload}
        />
      </div>

      {/* Sidebar-like sections */}
      <div className="grid gap-6 lg:grid-cols-2">
        {/* Category */}
        <div>
          <label className="mb-1 block text-sm font-medium text-foreground">
            Categorie
          </label>
          <select
            value={categoryId}
            onChange={(e) => setCategoryId(e.target.value)}
            className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
          >
            <option value="">Geen categorie</option>
            {categories.map((cat) => (
              <option key={cat.id} value={cat.id}>
                {cat.name}
              </option>
            ))}
          </select>
        </div>

        {/* Tags */}
        <div>
          <label className="mb-1 block text-sm font-medium text-foreground">
            Tags
          </label>
          <div className="rounded-lg border border-border bg-secondary p-3">
            {/* Selected tags */}
            <div className="mb-2 flex flex-wrap gap-1">
              {selectedTagIds.map((tagId) => {
                const tag = tags.find((t) => t.id === tagId);
                if (!tag) return null;
                return (
                  <span
                    key={tag.id}
                    className="inline-flex items-center gap-1 rounded-full bg-primary/10 px-2.5 py-0.5 text-xs font-medium text-primary"
                  >
                    {tag.name}
                    <button
                      type="button"
                      onClick={() => toggleTag(tag.id)}
                      className="ml-0.5 hover:text-primary/70"
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </span>
                );
              })}
            </div>

            {/* Tag search / add new */}
            <div className="relative">
              <input
                type="text"
                value={newTagName}
                onChange={(e) => {
                  setNewTagName(e.target.value);
                  setShowNewTagInput(true);
                }}
                onFocus={() => setShowNewTagInput(true)}
                placeholder="Zoek of maak tag..."
                className="w-full border-0 bg-transparent text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-0"
              />
              {showNewTagInput && (newTagName || filteredTags.length > 0) && (
                <div className="absolute left-0 right-0 top-full z-10 mt-1 max-h-40 overflow-y-auto rounded-lg border border-border bg-white shadow-lg">
                  {filteredTags
                    .filter((t) => !selectedTagIds.includes(t.id))
                    .map((tag) => (
                      <button
                        key={tag.id}
                        type="button"
                        onClick={() => {
                          toggleTag(tag.id);
                          setNewTagName("");
                          setShowNewTagInput(false);
                        }}
                        className="flex w-full items-center px-3 py-1.5 text-left text-sm text-foreground hover:bg-muted"
                      >
                        {tag.name}
                      </button>
                    ))}
                  {newTagName &&
                    !tags.some(
                      (t) =>
                        t.name.toLowerCase() === newTagName.toLowerCase(),
                    ) && (
                      <button
                        type="button"
                        onClick={() => {
                          // Parent should handle tag creation through onSave
                          // For now, we just close the dropdown
                          setNewTagName("");
                          setShowNewTagInput(false);
                        }}
                        className="flex w-full items-center gap-2 border-t border-border px-3 py-1.5 text-left text-sm text-primary hover:bg-muted"
                      >
                        <Plus className="h-3 w-3" />
                        Maak &quot;{newTagName}&quot; aan
                      </button>
                    )}
                </div>
              )}
            </div>

            {/* Click outside to close */}
            {showNewTagInput && (
              <div
                className="fixed inset-0 z-0"
                onClick={() => setShowNewTagInput(false)}
              />
            )}
          </div>
        </div>
      </div>

      {/* Featured Image */}
      <ImageUpload
        onUpload={async (file) => {
          const url = await onImageUpload(file);
          setFeaturedImage(url);
          return url;
        }}
        currentImage={featuredImage}
        onRemove={() => setFeaturedImage(null)}
        label="Uitgelichte afbeelding"
      />

      {/* SEO Section (collapsible) */}
      <div className="rounded-lg border border-border">
        <button
          type="button"
          onClick={() => setSeoOpen(!seoOpen)}
          className="flex w-full items-center justify-between px-4 py-3 text-left"
        >
          <span className="text-sm font-medium text-foreground">
            SEO-instellingen
          </span>
          {seoOpen ? (
            <ChevronUp className="h-4 w-4 text-muted-foreground" />
          ) : (
            <ChevronDown className="h-4 w-4 text-muted-foreground" />
          )}
        </button>
        {seoOpen && (
          <div className="space-y-4 border-t border-border px-4 py-4">
            <div>
              <label className="mb-1 block text-sm font-medium text-foreground">
                Meta-titel
              </label>
              <input
                type="text"
                value={metaTitle}
                onChange={(e) => setMetaTitle(e.target.value)}
                placeholder={title || "Meta-titel..."}
                className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
              <p className="mt-1 text-xs text-muted-foreground">
                {metaTitle.length}/60 tekens
              </p>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-foreground">
                Meta-beschrijving
              </label>
              <textarea
                value={metaDescription}
                onChange={(e) => setMetaDescription(e.target.value)}
                placeholder="Beschrijving voor zoekmachines..."
                rows={3}
                className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
              <p className="mt-1 text-xs text-muted-foreground">
                {metaDescription.length}/160 tekens
              </p>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-foreground">
                OG-afbeelding URL
              </label>
              <input
                type="url"
                value={ogImage}
                onChange={(e) => setOgImage(e.target.value)}
                placeholder="https://..."
                className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-foreground">
                Canonical URL
              </label>
              <input
                type="url"
                value={canonicalUrl}
                onChange={(e) => setCanonicalUrl(e.target.value)}
                placeholder="https://..."
                className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
              />
            </div>
          </div>
        )}
      </div>

      {/* Schedule Section */}
      <div className="rounded-lg border border-border px-4 py-4">
        <label className="mb-2 flex items-center gap-2 text-sm font-medium text-foreground">
          <Calendar className="h-4 w-4" />
          Inplannen
        </label>
        <input
          type="datetime-local"
          value={scheduledAt}
          onChange={(e) => setScheduledAt(e.target.value)}
          className="w-full rounded-lg border border-border bg-secondary px-3 py-2 text-sm text-foreground focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
        />
        {scheduledAt && (
          <p className="mt-1 text-xs text-muted-foreground">
            Wordt gepubliceerd op{" "}
            {new Date(scheduledAt).toLocaleDateString("nl-NL", {
              weekday: "long",
              day: "numeric",
              month: "long",
              year: "numeric",
              hour: "2-digit",
              minute: "2-digit",
            })}
          </p>
        )}
      </div>

      {/* Action Buttons */}
      <div className="flex flex-wrap items-center gap-3 border-t border-border pt-4">
        <button
          type="button"
          onClick={handleSave}
          disabled={isSaving || !title}
          className="inline-flex items-center gap-2 rounded-lg border border-border bg-white px-4 py-2 text-sm font-medium text-foreground hover:bg-muted disabled:opacity-50"
        >
          {isSaving ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Save className="h-4 w-4" />
          )}
          Opslaan als concept
        </button>

        <button
          type="button"
          onClick={handlePublish}
          disabled={isPublishing || !title}
          className="inline-flex items-center gap-2 rounded-lg bg-primary px-4 py-2 text-sm font-medium text-white hover:bg-primary/90 disabled:opacity-50"
        >
          {isPublishing ? (
            <Loader2 className="h-4 w-4 animate-spin" />
          ) : (
            <Send className="h-4 w-4" />
          )}
          Publiceren
        </button>

        {scheduledAt && (
          <button
            type="button"
            onClick={handleSchedule}
            disabled={isScheduling || !title || !scheduledAt}
            className="inline-flex items-center gap-2 rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 disabled:opacity-50"
          >
            {isScheduling ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Clock className="h-4 w-4" />
            )}
            Inplannen
          </button>
        )}
      </div>
    </div>
  );
}
